import { auth } from "@/lib/auth";
import { NextResponse } from "next/server";

interface TestimonialPayload {
  phone: string;
  subject: string;
  message: string;
  rating: string;
  fileName?: string;
  fileType?: string;
  fileBase64?: string;
}

const ALLOWED_MIME_TYPES = new Set([
  "application/pdf",
  "image/jpeg",
  "image/png",
  "image/webp",
]);

const MAX_FILE_SIZE_BYTES = 2 * 1024 * 1024;
const MAX_LENGTHS = {
  phone: 30,
  subject: 200,
  message: 5000,
};

function sanitize(value: unknown, maxLength: number): string {
  return typeof value === "string" ? value.trim().slice(0, maxLength) : "";
}

function base64Encode(buffer: ArrayBuffer): string {
  let binary = "";
  const bytes = new Uint8Array(buffer);

  for (const byte of bytes) {
    binary += String.fromCharCode(byte);
  }

  return Buffer.from(binary, "binary").toString("base64");
}

async function parseMultipartBody(request: Request) {
  const formData = await request.formData();
  const file = formData.get("referenceDocument");
  const fileRecord = file instanceof File ? file : null;

  const rawPayload = {
    phone: formData.get("phone"),
    subject: formData.get("subject"),
    message: formData.get("message"),
    rating: formData.get("rating"),
  };

  return {
    rawPayload,
    fileRecord,
  };
}

export async function POST(request: Request) {
  const session = await auth();

  if (!session?.user?.id || !session.user.email || session.user.provider !== "google") {
    return NextResponse.json(
      { error: "Authentication is required to submit a testimonial." },
      { status: 401 },
    );
  }

  const contentType = request.headers.get("content-type") ?? "";
  const isMultipart = contentType.includes("multipart/form-data");

  let payload: TestimonialPayload;
  let fileRecord: File | null = null;

  try {
    if (isMultipart) {
      const parsed = await parseMultipartBody(request);
      payload = {
        phone: String(parsed.rawPayload.phone ?? ""),
        subject: String(parsed.rawPayload.subject ?? ""),
        message: String(parsed.rawPayload.message ?? ""),
        rating: String(parsed.rawPayload.rating ?? ""),
      };
      fileRecord = parsed.fileRecord;
    } else {
      const body = await request.json().catch(() => null);

      if (!body || typeof body !== "object") {
        return NextResponse.json({ error: "Invalid request body." }, { status: 400 });
      }

      payload = {
        phone: typeof body.phone === "string" ? body.phone : "",
        subject: typeof body.subject === "string" ? body.subject : "",
        message: typeof body.message === "string" ? body.message : "",
        rating: typeof body.rating === "string" ? body.rating : "",
      };
    }
  } catch {
    return NextResponse.json({ error: "Invalid request body." }, { status: 400 });
  }

  if (!payload.phone.trim()) {
    return NextResponse.json({ error: "Phone number is required." }, { status: 400 });
  }

  if (!payload.subject.trim()) {
    return NextResponse.json({ error: "Subject is required." }, { status: 400 });
  }

  if (payload.message.trim().length < 20) {
    return NextResponse.json(
      { error: "Message must be at least 20 characters long." },
      { status: 400 },
    );
  }

  const rating = Number(payload.rating);
  if (!Number.isFinite(rating) || rating < 1 || rating > 5) {
    return NextResponse.json({ error: "Rating must be between 1 and 5." }, { status: 400 });
  }

  if (!/^[+\d][\d\s\-()]{6,19}$/.test(payload.phone.trim())) {
    return NextResponse.json({ error: "Enter a valid phone number." }, { status: 400 });
  }

  const cleanedPayload = {
    googleUserId: session.user.id,
    provider: session.user.provider,
    name: sanitize(session.user.name, 120),
    email: sanitize(session.user.email, 200),
    profileImageUrl: sanitize(session.user.image ?? "", 500),
    phone: sanitize(payload.phone, MAX_LENGTHS.phone),
    subject: sanitize(payload.subject, MAX_LENGTHS.subject),
    message: sanitize(payload.message, MAX_LENGTHS.message),
    rating,
    approvalStatus: "Pending",
  };

  if (!cleanedPayload.name || !cleanedPayload.email) {
    return NextResponse.json(
      { error: "A verified Google session is required to submit a testimonial." },
      { status: 401 },
    );
  }

  let fileData: {
    fileName?: string;
    fileType?: string;
    fileBase64?: string;
  } = {};

  if (fileRecord) {
    if (!ALLOWED_MIME_TYPES.has(fileRecord.type)) {
      return NextResponse.json(
        { error: "Only PDF, JPG, PNG, and WEBP files are allowed." },
        { status: 400 },
      );
    }

    if (fileRecord.size > MAX_FILE_SIZE_BYTES) {
      return NextResponse.json(
        { error: "Uploaded file must be 2MB or smaller." },
        { status: 400 },
      );
    }

    const fileBytes = await fileRecord.arrayBuffer();
    fileData = {
      fileName: fileRecord.name,
      fileType: fileRecord.type,
      fileBase64: base64Encode(fileBytes),
    };
  }

  const webhookUrl = process.env.TESTIMONIAL_WEBHOOK_URL;

  if (!webhookUrl) {
    console.error("TESTIMONIAL_WEBHOOK_URL is not configured.");
    return NextResponse.json(
      { error: "The testimonial form is not configured yet." },
      { status: 503 },
    );
  }

  try {
    const response = await fetch(webhookUrl, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        ...cleanedPayload,
        ...fileData,
        submittedAt: new Date().toISOString(),
      }),
      redirect: "follow",
      signal: AbortSignal.timeout(15_000),
    });

    if (!response.ok) {
      throw new Error(`Webhook responded with ${response.status}`);
    }

    const responseText = await response.text();
    let result: { ok?: boolean } | null = null;

    try {
      result = JSON.parse(responseText);
    } catch {
      throw new Error(`Webhook returned non-JSON response: ${responseText.slice(0, 300)}`);
    }

    if (result?.ok !== true) {
      throw new Error(`Webhook reported failure: ${responseText.slice(0, 300)}`);
    }

    return NextResponse.json({ ok: true });
  } catch (error) {
    console.error("Testimonial forwarding failed:", error);
    return NextResponse.json(
      { error: "Could not submit your testimonial. Please try again later." },
      { status: 502 },
    );
  }
}

