import { Star } from "lucide-react";
import { cn } from "@/lib/utils";

interface StarRatingProps {
  value: number;
  onChange: (value: number) => void;
  disabled?: boolean;
}

export function StarRating({ value, onChange, disabled = false }: StarRatingProps) {
  return (
    <div className="flex items-center gap-2">
      {[1, 2, 3, 4, 5].map((star) => (
        <button
          key={star}
          type="button"
          className={cn(
            "rounded-full p-1 transition-colors",
            disabled && "cursor-not-allowed opacity-60",
          )}
          aria-label={`Rate ${star} out of 5`}
          aria-pressed={value === star}
          disabled={disabled}
          onClick={() => onChange(star)}
        >
          <Star
            className={cn(
              "h-6 w-6",
              star <= value ? "fill-yellow-400 text-yellow-400" : "text-muted",
            )}
          />
        </button>
      ))}
      <span className="ml-1 text-sm font-medium text-muted">
        {value}/5
      </span>
    </div>
  );
}

"use client";

import { useMemo, useState } from "react";
import { signIn, useSession } from "next-auth/react";
import {
  CheckCircle2,
  FileText,
  Loader2,
  Send,
  TriangleAlert,
  Upload,
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { cn } from "@/lib/utils";
import { StarRating } from "@/components/testimonials/star-rating";

interface FormState {
  phone: string;
  subject: string;
  message: string;
  rating: number;
}

type FormErrors = Partial<Record<keyof FormState, string>>;
type SubmitStatus = "idle" | "sending" | "success" | "error";

const initialState: FormState = {
  phone: "",
  subject: "",
  message: "",
  rating: 5,
};

const inputStyles =
  "card-surface w-full rounded-xl px-4 py-3 text-sm outline-none placeholder:text-muted focus:border-primary";

function generateInitials(name: string) {
  return name
    .split(/\s+/)
    .filter(Boolean)
    .slice(0, 2)
    .map((part) => part[0]?.toUpperCase() ?? "")
    .join("") || "G";
}

export function TestimonialForm() {
  const { data: session, status } = useSession();
  const [form, setForm] = useState<FormState>(initialState);
  const [errors, setErrors] = useState<FormErrors>({});
  const [statusState, setStatusState] = useState<SubmitStatus>("idle");
  const [file, setFile] = useState<File | null>(null);

  const profileName = session?.user?.name ?? "Google User";
  const profileEmail = session?.user?.email ?? "";
  const profileImage = session?.user?.image ?? "";

  const initials = useMemo(() => generateInitials(profileName), [profileName]);

  const validate = (): FormErrors => {
    const nextErrors: FormErrors = {};

    if (!form.phone.trim() || !/^[+\d][\d\s\-()]{6,19}$/.test(form.phone.trim())) {
      nextErrors.phone = "Enter a valid phone number.";
    }

    if (!form.subject.trim()) {
      nextErrors.subject = "Subject is required.";
    }

    if (form.message.trim().length < 20) {
      nextErrors.message = "Please write at least 20 characters.";
    }

    if (!Number.isFinite(form.rating) || form.rating < 1 || form.rating > 5) {
      nextErrors.rating = "Choose a rating from 1 to 5 stars.";
    }

    return nextErrors;
  };

  const handleChange = (
    event: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>,
  ) => {
    const { name, value } = event.target;
    setForm((current) => ({ ...current, [name]: name === "rating" ? Number(value) : value }));
    setErrors((current) => ({ ...current, [name]: undefined }));
  };

  const handleSubmit = async (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    const nextErrors = validate();
    setErrors(nextErrors);

    if (Object.keys(nextErrors).length > 0) {
      return;
    }

    setStatusState("sending");

    try {
      const data = new FormData();
      data.append("phone", form.phone.trim());
      data.append("subject", form.subject.trim());
      data.append("message", form.message.trim());
      data.append("rating", String(form.rating));

      if (file) {
        data.append("referenceDocument", file);
      }

      const response = await fetch("/api/testimonials", {
        method: "POST",
        body: data,
      });

      if (!response.ok) {
        const result = await response.json().catch(() => null);
        throw new Error(result?.error ?? "Request failed.");
      }

      setStatusState("success");
      setForm(initialState);
      setFile(null);
    } catch (error) {
      console.error(error);
      setStatusState("error");
    }
  };

  if (status === "loading") {
    return (
      <Card className="flex items-center justify-center gap-3 py-10">
        <Loader2 className="h-5 w-5 animate-spin text-primary" aria-hidden="true" />
        <span className="text-sm text-muted">Checking Google authentication…</span>
      </Card>
    );
  }

  if (!session?.user) {
    return (
      <Card className="space-y-4">
        <h3 className="text-xl font-bold tracking-tight">Verified testimonial submission</h3>
        <p className="text-sm leading-relaxed text-muted">
          To maintain authenticity and prevent fake reviews, testimonials are accepted only
          from verified Google accounts.
        </p>
        <Button type="button" onClick={() => signIn("google", { callbackUrl: "/testimonials" })}>
          Continue with Google
        </Button>
      </Card>
    );
  }

  if (statusState === "success") {
    return (
      <Card className="flex flex-col items-center rounded-2xl bg-primary-soft px-6 py-12 text-center">
        <CheckCircle2 className="h-12 w-12 text-primary" aria-hidden="true" />
        <h3 className="mt-4 text-xl font-bold tracking-tight">
          Verified testimonial submitted
        </h3>
        <p className="mt-2 max-w-sm text-sm leading-relaxed text-muted">
          Your testimonial has been received and is now pending manual approval.
        </p>
        <button
          type="button"
          onClick={() => setStatusState("idle")}
