export function TestimonialForm() {
  const { data: session, status } = useSession();
  const [form, setForm] = useState<FormState>(initialState);
  const [errors, setErrors] = useState<FormErrors>({});
  const [statusState, setStatusState] = useState<SubmitStatus>("idle");
  const [file, setFile] = useState<File | null>(null);

  const profileName = session?.user?.name ?? "Google User";
  const profileEmail = session?.user?.email ?? "";
  const profileImage = session?.user?.image ?? "";

  const initials = useMemo(() => generateInitials(profileName), [profileName]);

  const validate = (): FormErrors => {
    const nextErrors: FormErrors = {};

    if (!form.phone.trim() || !/^[+\d][\d\s\-()]{6,19}$/.test(form.phone.trim())) {
      nextErrors.phone = "Enter a valid phone number.";
    }

    if (!form.subject.trim()) {
      nextErrors.subject = "Subject is required.";
    }

    if (form.message.trim().length < 20) {
      nextErrors.message = "Please write at least 20 characters.";
    }

    if (!Number.isFinite(form.rating) || form.rating < 1 || form.rating > 5) {
      nextErrors.rating = "Choose a rating from 1 to 5 stars.";
    }

    return nextErrors;
  };

  const handleChange = (
    event: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>,
  ) => {
    const { name, value } = event.target;
    setForm((current) => ({ ...current, [name]: name === "rating" ? Number(value) : value }));
    setErrors((current) => ({ ...current, [name]: undefined }));
  };

