                {errors.phone}
              </p>
            ) : null}
          </div>

          <div>
            <label htmlFor="testimonial-subject" className="mb-2 block text-sm font-medium">
              Subject
            </label>
            <input
              id="testimonial-subject"
              name="subject"
              type="text"
              placeholder="Project collaboration"
              value={form.subject}
              onChange={handleChange}
              aria-invalid={Boolean(errors.subject)}
              aria-describedby={errors.subject ? "testimonial-subject-error" : undefined}
              className={cn(inputStyles, errors.subject && "border-red-500")}
            />
            {errors.subject ? (
              <p id="testimonial-subject-error" role="alert" className="mt-1.5 text-xs text-red-500">
                {errors.subject}
              </p>
            ) : null}
          </div>
        </div>

        <div>
          <label htmlFor="testimonial-message" className="mb-2 block text-sm font-medium">
            Message
          </label>
          <textarea
            id="testimonial-message"
            name="message"
            rows={6}
            placeholder="Share your recommendation, collaboration, or professional experience…"
            value={form.message}
            onChange={handleChange}
            aria-invalid={Boolean(errors.message)}
            aria-describedby={errors.message ? "testimonial-message-error" : undefined}
            className={cn(inputStyles, "resize-y", errors.message && "border-red-500")}
          />
          {errors.message ? (
            <p id="testimonial-message-error" role="alert" className="mt-1.5 text-xs text-red-500">
              {errors.message}
            </p>
          ) : null}
        </div>

        <div>
          <label className="mb-2 block text-sm font-medium">Rating</label>
          <StarRating
            value={form.rating}
            onChange={(nextValue) => {
              setForm((current) => ({ ...current, rating: nextValue }));
              setErrors((current) => ({ ...current, rating: undefined }));
            }}
          />
          {errors.rating ? (
            <p role="alert" className="mt-1.5 text-xs text-red-500">
              {errors.rating}
            </p>
          ) : null}
        </div>

        <div>
          <label htmlFor="testimonial-document" className="mb-2 block text-sm font-medium">
            Upload Reference Letter <span className="font-normal text-muted">(optional)</span>
          </label>
          <label className="flex cursor-pointer items-center justify-between gap-3 rounded-2xl border border-dashed border-border-strong px-4 py-3 text-sm text-muted transition-colors hover:border-primary hover:text-primary">
            <span className="flex items-center gap-2">
              <Upload className="h-4 w-4" aria-hidden="true" />
              {file ? file.name : "Choose a PDF, JPG, PNG, or WEBP file"}
            </span>
            <span className="text-xs">Max 2MB</span>
            <input
              id="testimonial-document"
              type="file"
              accept=".pdf,.jpg,.jpeg,.png,.webp,image/png,image/jpeg,image/webp,application/pdf"
              className="hidden"
              onChange={(event) => setFile(event.target.files?.[0] ?? null)}
            />
          </label>
          {file ? (
            <div className="mt-2 flex items-center gap-2 text-sm text-muted">
              <FileText className="h-4 w-4 text-primary" aria-hidden="true" />
              <span>{file.name}</span>
            </div>
          ) : null}
        </div>

        <div className="flex flex-wrap items-center gap-4">
          <Button type="submit" size="lg" disabled={statusState === "sending"}>
            {statusState === "sending" ? (
              <>
                <Loader2 className="h-4 w-4 animate-spin" aria-hidden="true" />
                Submitting…
              </>
            ) : (
              <>
                <Send className="h-4 w-4" aria-hidden="true" />
                Submit testimonial
              </>
            )}
          </Button>
          <Badge variant="outline">Verified through Google authentication</Badge>
        </div>

        {statusState === "error" ? (
          <p
            role="alert"
            className="flex items-start gap-2 rounded-xl bg-red-500/10 px-4 py-3 text-sm text-red-500"
          >
            <TriangleAlert className="mt-0.5 h-4 w-4 shrink-0" aria-hidden="true" />
            <span>Something went wrong submitting your testimonial. Please try again.</span>
          </p>
        ) : null}
      </form>
    </Card>
  );
}
