import { testimonials } from "@/data/testimonials";
import { createPageMetadata } from "@/lib/metadata";
import { Star } from "lucide-react";

function generateInitials(name: string) {
  return name
    .split(/\s+/)
    .filter(Boolean)
    .slice(0, 2)
    .map((part) => part[0]?.toUpperCase() ?? "")
    .join("") || "G";
}

export async function generateMetadata({
  params,
}: {
  params: Promise<{ id: string }>;
}) {
  const { id } = await params;
  const testimonial = testimonials.find((item) => item.id === id);

  if (!testimonial) {
    return createPageMetadata({
      title: "Testimonial Not Found",
      description: "This testimonial could not be found.",
      path: `/testimonials/${id}`,
    });
  }

  return createPageMetadata({
    title: testimonial.name,
    description: testimonial.subject,
    path: `/testimonials/${id}`,
  });
}

export default async function TestimonialDetailPage({
  params,
}: {
  params: Promise<{ id: string }>;
}) {
  const { id } = await params;
  const testimonial = testimonials.find((item) => item.id === id);

  if (!testimonial) {
    notFound();
  }

  return (
    <>
      <PageHeader
        eyebrow="Verified Recommendation"
        title={testimonial.name}
        description={testimonial.subject}
      />
      <Section className="pt-0 sm:pt-0">
        <Card className="mx-auto max-w-3xl space-y-6">
          <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
            <div className="flex items-center gap-4">
              {testimonial.profileImageUrl ? (
                <img
                  src={testimonial.profileImageUrl}
                  alt={testimonial.name}
                  className="h-14 w-14 rounded-full object-cover"
                />
              ) : (
                <span className="flex h-14 w-14 items-center justify-center rounded-full bg-primary-soft text-lg font-bold text-primary">
                  {generateInitials(testimonial.name)}
                </span>
              )}
              <div>
                <p className="text-lg font-semibold">{testimonial.name}</p>
                <p className="text-sm text-muted">{testimonial.subject}</p>
              </div>
            </div>
            <div className="flex flex-wrap items-center gap-2">
              <Badge variant="primary">Verified</Badge>
              {testimonial.approvedAt ? (
                <Badge variant="outline">Approved {testimonial.approvedAt}</Badge>
              ) : null}
            </div>
          </div>

          <div className="flex items-center gap-2 text-yellow-400">
            {Array.from({ length: 5 }, (_, index) => (
              <Star
                key={index}
                className={`h-5 w-5 ${index < testimonial.rating ? "fill-current" : "text-muted"}`}
                aria-hidden="true"
              />
            ))}
            <span className="text-sm font-medium text-muted">{testimonial.rating}/5</span>
          </div>

          <div className="rounded-2xl border border-border bg-primary-soft/40 p-5 text-base leading-relaxed text-foreground">
            {testimonial.message}
          </div>

          <div className="flex flex-wrap items-center gap-3">
            <ButtonLink href="/testimonials" variant="outline">
              Back to testimonials
            </ButtonLink>
            <Link href="/contact" className="text-sm font-medium text-primary hover:underline">
              Contact me
            </Link>
          </div>
        </Card>
      </Section>
    </>
  );
}
